  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



vec2 uv1 = (vUv-.5) * uAspect.xy;

vec2 uv6 = uv1;
float z = q31*length((abs(uv1.x)-abs(uv1.y)));
vec2 d = normalize(uv1);
vec2 rs = clamp(tan(z)*d,-4,1);
vUv += .0*lum(GetBlur1(vUv))*vec2 (0,1);
